export default function SettingsModal({
  settingsOpen,
  onClose,
  handleSubmit,
  showUserMessages,
  setShowUserMessages,
  showSidebar,
  setShowSidebar,
  showSendButton,
  setShowSendButton,
}) {
  if (!settingsOpen) {
    return null;
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <h2>Settings</h2>
        <form
          onSubmit={(e) => {
            e.preventDefault();
            handleSubmit();
          }}
        >
          <label>
            User Messages:
            <input
              type="checkbox"
              name="usermessages"
              checked={showUserMessages}
              onChange={(e) => setShowUserMessages(e.target.checked)}
            />
          </label>
          <label>
            Sidebar:
            <input
              type="checkbox"
              name="sidebar"
              checked={showSidebar}
              onChange={(e) => setShowSidebar(e.target.checked)}
            />
          </label>
          <label>
            Send Button:
            <input
              type="checkbox"
              name="sendbutton"
              checked={showSidebar}
              onChange={(e) => setShowSidebar(e.target.checked)}
            />
          </label>
          <button type="submit" className="modal-button">
            Save
          </button>
        </form>
      </div>
    </div>
  );
}
